  2→import { RecordId, type Surreal } from "surrealdb";
  3→import { HttpError } from "../http/errors";
  4→import { elapsedMs, logError, logInfo } from "../http/observability";
  5→import { createEmbedding } from "./embedding-writeback";
  6→import { extractStructuredGraph } from "./extract-graph";
