321→function sanitizeAssistantSuggestions(suggestions: string[], limit: number): string[] {
322→  return [...new Set(suggestions.map((value) => value.trim()))]
323→    .filter((value) => value.length > 0 && value.length <= 140)
324→    .slice(0, limit);
